import type { Transaction } from '@/types';
import { StatusBadge } from '@/components/ui/StatusBadge';
import { formatCurrency, formatRelativeTime, getInitials } from '@/lib/formatters';

interface TransactionRowProps {
  transaction: Transaction;
}

export function TransactionRow({ transaction }: TransactionRowProps) {
  const { recipientName, recipientBank, senderAmount, senderCurrency, receiverAmount, receiverCurrency, status, createdAt, narration } = transaction;
  const initials = getInitials(recipientName);
  const hue = recipientName.split('').reduce((acc, c) => acc + c.charCodeAt(0), 0) % 360;
  return (
    <div className="group flex items-center gap-4 rounded-xl px-4 py-3.5 transition-colors duration-150 hover:bg-white/[0.03] cursor-default">
      <div className="flex h-9 w-9 flex-shrink-0 items-center justify-center rounded-full text-[11px] font-bold"
        style={{ background: `hsl(${hue} 60% 15%)`, color: `hsl(${hue} 80% 70%)`, border: `1px solid hsl(${hue} 60% 22%)` }}>
        {initials}
      </div>
      <div className="flex-1 min-w-0">
        <p className="text-sm font-medium text-zinc-200 truncate leading-none">{recipientName}</p>
        <p className="mt-1 text-[11px] text-zinc-600 truncate">{narration ?? recipientBank}</p>
      </div>
      <div className="hidden sm:block flex-shrink-0"><StatusBadge status={status} /></div>
      <p className="hidden md:block w-16 flex-shrink-0 text-right text-[11px] font-mono text-zinc-600">{formatRelativeTime(createdAt)}</p>
      <div className="flex-shrink-0 text-right">
        <p className="text-sm font-mono font-semibold text-red-400">-{formatCurrency(senderAmount, senderCurrency)}</p>
        <p className="mt-0.5 text-[10.5px] font-mono text-zinc-600">≈ {formatCurrency(receiverAmount, receiverCurrency)}</p>
      </div>
    </div>
  );
}
